import{_ as e,c as a,o,a1 as d}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Сбой аутентификации: устранение ошибки 401 | Antigravity-Manager","description":"Научитесь механизму аутентификации прокси Antigravity Tools, устраните ошибки 401. Найдите проблему в порядке auth_mode, api_key, Header, поймите правила режима auto и исключение /healthz, избегайте ошибок приоритета заголовка.","frontmatter":{"title":"Сбой аутентификации: устранение ошибки 401 | Antigravity-Manager","sidebarTitle":"Решить 401 за 3 минуты","subtitle":"401/Сбой аутентификации: сначала посмотрите auth_mode, затем заголовки","description":"Научитесь механизму аутентификации прокси Antigravity Tools, устраните ошибки 401. Найдите проблему в порядке auth_mode, api_key, Header, поймите правила режима auto и исключение /healthz, избегайте ошибок приоритета заголовка.","tags":["FAQ","Аутентификация","401","API Key"],"prerequisite":["start-proxy-and-first-client"],"order":2},"headers":[],"relativePath":"ru/lbjlaq/Antigravity-Manager/faq/auth-401/index.md","filePath":"ru/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"}'),r={name:"ru/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"};function i(s,t,l,c,h,n){return o(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="_401-сбои-аутентификации-сначала-посмотрите-auth-mode-затем-заголовки" tabindex="-1">401/Сбой аутентификации: сначала посмотрите auth_mode, затем заголовки <a class="header-anchor" href="#_401-сбои-аутентификации-сначала-посмотрите-auth-mode-затем-заголовки" aria-label="Permalink to &quot;401/Сбой аутентификации: сначала посмотрите auth_mode, затем заголовки&quot;">​</a></h1><h2 id="чему-вы-научитесь" tabindex="-1">Чему вы научитесь <a class="header-anchor" href="#чему-вы-научитесь" aria-label="Permalink to &quot;Чему вы научитесь&quot;">​</a></h2><ul><li>За 3 минуты определить, блокируется ли 401 middleware аутентификации Antigravity Tools</li><li>Понять &quot;фактическое эффективное значение&quot; четырех режимов <code>proxy.auth_mode</code> (особенно <code>auto</code>) при вашей текущей конфигурации</li><li>Использовать правильные заголовки API Key (и избегать ошибок приоритета заголовков), чтобы запрос прошел</li></ul><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><p>Клиент вызывает локальный reverse proxy и получает ошибку <code>401 Unauthorized</code>:</p><ul><li>Python/OpenAI SDK: выбрасывает <code>AuthenticationError</code></li><li>curl: возвращает <code>HTTP/1.1 401 Unauthorized</code></li><li>HTTP клиент: код состояния ответа 401</li></ul><h2 id="что-такое-401-сбои-аутентификации" tabindex="-1">Что такое 401/Сбой аутентификации? <a class="header-anchor" href="#что-такое-401-сбои-аутентификации" aria-label="Permalink to &quot;Что такое 401/Сбой аутентификации?&quot;">​</a></h2><p><strong>401 Unauthorized</strong> в Antigravity Tools чаще всего означает: прокси включил аутентификацию (определяется <code>proxy.auth_mode</code>), но запрос не принес правильный API Key или принес неправильный заголовок с более высоким приоритетом, поэтому <code>auth_middleware()</code> возвращает 401.</p><div class="info custom-block"><p class="custom-block-title">Сначала подтвердите, блокирует ли &quot;прокси&quot;</p><p>Апстрим платформы также может вернуть 401, но это FAQ касается только &quot;401, вызванного аутентификацией прокси&quot;. Вы можете быстро отличить с помощью <code>/healthz</code> ниже.</p></div><h2 id="быстрое-устранение-неполадок-делаите-в-этом-порядке" tabindex="-1">Быстрое устранение неполадок (делайте в этом порядке) <a class="header-anchor" href="#быстрое-устранение-неполадок-делаите-в-этом-порядке" aria-label="Permalink to &quot;Быстрое устранение неполадок (делайте в этом порядке)&quot;">​</a></h2><h3 id="шаг-1-используите-healthz-чтобы-определить-блокирует-ли-аутентификация" tabindex="-1">Шаг 1: Используйте <code>/healthz</code>, чтобы определить, &quot;блокирует ли аутентификация&quot; <a class="header-anchor" href="#шаг-1-используите-healthz-чтобы-определить-блокирует-ли-аутентификация" aria-label="Permalink to &quot;Шаг 1: Используйте `/healthz`, чтобы определить, &quot;блокирует ли аутентификация&quot;&quot;">​</a></h3><p><strong>Зачем</strong><code>all_except_health</code> пропустит <code>/healthz</code>, но заблокирует другие маршруты; это поможет быстро определить, 401 ли от слоя аутентификации прокси.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Без заголовков аутентификации</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/healthz</span></span></code></pre></div><p><strong>Вы должны увидеть</strong></p><ul><li>При <code>auth_mode=all_except_health</code> (или <code>auto</code> и <code>allow_lan_access=true</code>): обычно возвращает <code>200</code></li><li>При <code>auth_mode=strict</code>: возвращает <code>401</code></li></ul><div class="tip custom-block"><p class="custom-block-title"><code>/healthz</code> в слое маршрутов - GET</p><p>В маршрутах прокси регистрируется <code>GET /healthz</code> (см. <code>src-tauri/src/proxy/server.rs</code>).</p></div><hr><h3 id="шаг-2-подтвердите-фактическое-эффективное-значение-auth-mode-особенно-auto" tabindex="-1">Шаг 2: Подтвердите &quot;фактическое эффективное значение&quot; <code>auth_mode</code> (особенно <code>auto</code>) <a class="header-anchor" href="#шаг-2-подтвердите-фактическое-эффективное-значение-auth-mode-особенно-auto" aria-label="Permalink to &quot;Шаг 2: Подтвердите &quot;фактическое эффективное значение&quot; `auth_mode` (особенно `auto`)&quot;">​</a></h3><p><strong>Зачем</strong><code>auto</code> - это не &quot;независимая стратегия&quot;, она рассчитывает реальный режим выполнения в зависимости от <code>allow_lan_access</code>.</p><table tabindex="0"><thead><tr><th><code>proxy.auth_mode</code></th><th>Дополнительные условия</th><th>Фактическое эффективное значение (effective mode)</th></tr></thead><tbody><tr><td><code>off</code></td><td>-</td><td><code>off</code></td></tr><tr><td><code>strict</code></td><td>-</td><td><code>strict</code></td></tr><tr><td><code>all_except_health</code></td><td>-</td><td><code>all_except_health</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=false</code></td><td><code>off</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=true</code></td><td><code>all_except_health</code></td></tr></tbody></table><p><strong>Вы можете проверить в GUI на странице API Proxy</strong>: <code>Allow LAN Access</code> и <code>Auth Mode</code>.</p><hr><h3 id="шаг-3-подтвердите-что-api-key-не-пуст-и-вы-используете-одно-и-то-же-значение" tabindex="-1">Шаг 3: Подтвердите, что <code>api_key</code> не пуст, и вы используете одно и то же значение <a class="header-anchor" href="#шаг-3-подтвердите-что-api-key-не-пуст-и-вы-используете-одно-и-то-же-значение" aria-label="Permalink to &quot;Шаг 3: Подтвердите, что `api_key` не пуст, и вы используете одно и то же значение&quot;">​</a></h3><p><strong>Зачем</strong> Когда аутентификация включена, если <code>proxy.api_key</code> пуст, <code>auth_middleware()</code> сразу отклонит все запросы и запишет ошибку в лог.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Proxy auth is enabled but api_key is empty; denying request</span></span></code></pre></div><p><strong>Вы должны увидеть</strong></p><ul><li>На странице API Proxy вы можете увидеть ключ, начинающийся с <code>sk-</code> (значение по умолчанию в <code>ProxyConfig::default()</code> будет автоматически сгенерировано)</li><li>После нажатия &quot;Regenerate/редактировать&quot; и сохранения, внешние запросы сразу проверяются по новому ключу (перезапуск не требуется)</li></ul><hr><h3 id="шаг-4-попробуите-один-раз-с-самым-простым-заголовком-сначала-не-используите-сложные-sdk" tabindex="-1">Шаг 4: Попробуйте один раз с самым простым заголовком (сначала не используйте сложные SDK) <a class="header-anchor" href="#шаг-4-попробуите-один-раз-с-самым-простым-заголовком-сначала-не-используите-сложные-sdk" aria-label="Permalink to &quot;Шаг 4: Попробуйте один раз с самым простым заголовком (сначала не используйте сложные SDK)&quot;">​</a></h3><p><strong>Зачем</strong> Middleware сначала считывает <code>Authorization</code>, затем <code>x-api-key</code>, наконец <code>x-goog-api-key</code>. Если вы отправили несколько заголовков одновременно, и первый неправильный, даже если следующий правильный, он не будет использован.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Рекомендуемый формат: Authorization + Bearer</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><p><strong>Вы должны увидеть</strong>: <code>HTTP/1.1 200 OK</code> (или минимум больше не 401)</p><div class="info custom-block"><p class="custom-block-title">Детали совместимости прокси с Authorization</p><p><code>auth_middleware()</code> разобьет значение <code>Authorization</code> по префиксу <code>Bearer </code> один раз; если нет префикса <code>Bearer </code>, все значение будет использовано как ключ для сравнения. В документации все равно рекомендуется <code>Authorization: Bearer &lt;key&gt;</code> (более соответствует общепринятым соглашениям SDK).</p></div><p><strong>Если вы должны использовать <code>x-api-key</code></strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;x-api-key: sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><hr><h2 id="распространенные-ошибки-все-реально-возникают-в-исходном-коде" tabindex="-1">Распространенные ошибки (все реально возникают в исходном коде) <a class="header-anchor" href="#распространенные-ошибки-все-реально-возникают-в-исходном-коде" aria-label="Permalink to &quot;Распространенные ошибки (все реально возникают в исходном коде)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Симптом</th><th>Реальная причина</th><th>Как изменить</th></tr></thead><tbody><tr><td><code>auth_mode=auto</code>, но локальный вызов все равно 401</td><td><code>allow_lan_access=true</code> вызывает <code>auto</code> действовать как <code>all_except_health</code></td><td>Отключите <code>allow_lan_access</code> или попросите клиента принести ключ</td></tr><tr><td>Вы думаете &quot;я явно принес x-api-key&quot;, но все равно 401</td><td>Одновременно принес неправильный <code>Authorization</code>, middleware использует его приоритетно</td><td>Удалите лишние заголовки, оставьте только тот, который вы уверены правильный</td></tr><tr><td><code>Authorization: Bearer&lt;key&gt;</code> все равно 401</td><td>После <code>Bearer</code> нет пробела, нельзя отделить по префиксу <code>Bearer </code></td><td>Измените на <code>Authorization: Bearer &lt;key&gt;</code></td></tr><tr><td>Все запросы 401, в логах появляется <code>api_key is empty</code></td><td><code>proxy.api_key</code> пуст</td><td>В GUI сгенерируйте/настройте непустой ключ снова</td></tr></tbody></table><h2 id="краткии-итог-урока" tabindex="-1">Краткий итог урока <a class="header-anchor" href="#краткии-итог-урока" aria-label="Permalink to &quot;Краткий итог урока&quot;">​</a></h2><ul><li>Сначала используйте <code>/healthz</code>, чтобы определить, 401 ли от слоя аутентификации прокси</li><li>Затем подтвердите <code>auth_mode</code> (особенно effective mode <code>auto</code>)</li><li>Наконец, принесьте один правильный заголовок для проверки (избегайте ошибок приоритета заголовков)</li></ul><h2 id="следующии-урок预告" tabindex="-1">Следующий урок预告 <a class="header-anchor" href="#следующии-урок预告" aria-label="Permalink to &quot;Следующий урок预告&quot;">​</a></h2><blockquote><p>Следующий урок мы изучим <strong><a href="./../429-rotation/">429/Ошибка емкости: правильные ожидания ротации аккаунтов и заблуждения об исчерпании емкости модели</a></strong>.</p><p>Вы узнаете:</p><ul><li>429 - это &quot;недостаток квоты&quot; или &quot;ограничение скорости апстрима&quot;</li><li>Правильные ожидания ротации аккаунтов (когда автоматически переключается, а когда нет)</li><li>С помощью конфигурации снизить вероятность 429</li></ul></blockquote><hr><h2 id="приложение-справка-по-исходному-коду" tabindex="-1">Приложение: Справка по исходному коду <a class="header-anchor" href="#приложение-справка-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справка по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы увидеть местоположение исходного кода</strong></summary><blockquote><p>Обновлено: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Строки</th></tr></thead><tbody><tr><td>Перечисление ProxyAuthMode</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L5-L18" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>5-18</td></tr><tr><td>ProxyConfig: allow_lan_access/auth_mode/api_key и значения по умолчанию</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-258</td></tr><tr><td>Разбор режима auto (effective_auth_mode)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/security.rs#L1-L30" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/security.rs</code></a></td><td>1-30</td></tr><tr><td>Middleware аутентификации (извлечение заголовков и приоритет, исключение /healthz, разрешение OPTIONS)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/middleware/auth.rs#L14-L77" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/middleware/auth.rs</code></a></td><td>14-77</td></tr><tr><td>Регистрация маршрута /healthz и порядок middleware</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/server.rs#L170-L193" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/server.rs</code></a></td><td>170-193</td></tr><tr><td>Документация аутентификации (режимы и соглашения клиентов)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/docs/proxy/auth.md#L1-L45" target="_blank" rel="noreferrer"><code>docs/proxy/auth.md</code></a></td><td>1-45</td></tr></tbody></table><p><strong>Ключевые перечисления</strong>:</p><ul><li><code>ProxyAuthMode::{Off, Strict, AllExceptHealth, Auto}</code>: режимы аутентификации</li></ul><p><strong>Ключевые функции</strong>:</p><ul><li><code>ProxySecurityConfig::effective_auth_mode()</code>: разобрать <code>auto</code> в реальную стратегию</li><li><code>auth_middleware()</code>: выполнить аутентификацию (включая порядок извлечения заголовков и исключение /healthz)</li></ul></details>',45)])])}const g=e(r,[["render",i]]);export{p as __pageData,g as default};
